            data: testImageData,
            mediaType: 'image/png',
          },
        ],
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      const requestBody = await server.calls[0].requestBodyJson;
      expect(requestBody.input.image).toMatch(/^data:image\/png;base64,/);
      expect(requestBody.input.prompt).toBe('Transform this image');
    });

