import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { Resolvable } from '@ai-sdk/provider-utils';
import {
  combineHeaders,
  createJsonResponseHandler,
  FetchFunction,
  InferSchema,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  resolve,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import { pixelArtFailedResponseHandler } from './pixelart-error';
import { PixelArtImageModelId } from './pixelart-image-settings';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    aspectRatio,
    size,
    seed,
    providerOptions,
    headers,
    abortSignal,
    files,
    mask,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported-setting',
        setting: 'aspectRatio',
        details:
          'PixelArt does not support aspect ratio. Use size instead.',
      });
    }

    if (files != null && files.length > 0) {
      warnings.push({
        type: 'other',
        message: 'PixelArt does not support image input files.',
      });
    }

    if (mask != null) {
      warnings.push({
        type: 'other',
        message: 'PixelArt does not support mask input.',
      });
    }

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(await resolve(this.config.headers), headers),
      body: {
        prompt,
        n,
        size,
        seed,
        ...(pixelArtOptions?.style != null
          ? { style: pixelArtOptions.style }
          : {}),
        ...(pixelArtOptions?.pixelDensity != null
          ? { pixel_density: pixelArtOptions.pixelDensity }
          : {}),
      },
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtImageResponseSchema,
      ),
      failedResponseHandler: pixelArtFailedResponseHandler,
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.data.map(item => {
        const binaryString = atob(item.b64_json);
        return Uint8Array.from(binaryString, c => c.charCodeAt(0));
      }),
      warnings,
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
    };
  }
}

const pixelArtImageResponseSchema = z.object({
  data: z.array(
    z.object({
      b64_json: z.string(),
    }),
  ),
});

/**
 * Provider options schema for PixelArt image generation.
 */
export const pixelArtImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z
      .object({
        /**
         * The visual style of the generated image.
         * - "pixel": Classic pixel art style
         * - "retro": Retro-inspired pixel art
         * - "8bit": 8-bit video game aesthetic
         */
        style: z.enum(['pixel', 'retro', '8bit']).nullish(),

        /**
         * The pixel density of the generated image.
         * Higher values produce more detailed pixel art.
         */
        pixelDensity: z.number().positive().nullish(),
      })
      .passthrough(),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelArtImageModelOptionsSchema
>;

