import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, it, expect, vi } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';
import { createPixelArt } from './pixelart-provider';

vi.mock('./version', () => ({
  VERSION: '0.0.0-test',
}));

const prompt = 'A tiny hero on a grand adventure';

const provider = createPixelArt({ apiKey: 'test-api-key' });
const model = provider.image('pixelart-standard');

// base64 of "test-image-data"
const TEST_B64 = Buffer.from('test-image-data').toString('base64');

describe('doGenerate', () => {
  const testDate = new Date(2024, 0, 1);

  const server = createTestServer({
    'https://api.pixelart.ai/*': {
      response: {
        type: 'json-value',
        body: {
          data: [{ b64_json: TEST_B64 }],
        },
      },
    },
  });

  it('should pass the prompt, n, size, style, and pixelDensity in the request body', async () => {
    await model.doGenerate({
      prompt,
      n: 2,
      size: '512x512',
      aspectRatio: undefined,
      seed: 42,
      providerOptions: {
        pixelart: {
          style: 'pixel',
          pixelDensity: 8,
        },
        other: {
          ignored: true,
        },
      },
      files: undefined,
      mask: undefined,
    });

    expect(await server.calls[0].requestBodyJson).toStrictEqual({
      prompt,
      n: 2,
      size: '512x512',
      seed: 42,
      style: 'pixel',
      pixel_density: 8,
    });
  });

  it('should call the correct URL', async () => {
    await model.doGenerate({
      prompt,
      n: 1,
      size: undefined,
      aspectRatio: undefined,
      seed: undefined,
      providerOptions: {},
      files: undefined,
      mask: undefined,
    });

    expect(server.calls[0].requestMethod).toStrictEqual('POST');
    expect(server.calls[0].requestUrl).toStrictEqual(
      'https://api.pixelart.ai/v1/images/generate',
    );
  });

  it('should pass auth header, custom headers, and user-agent', async () => {
    const providerWithHeaders = createPixelArt({
      apiKey: 'test-api-key',
      headers: {
        'X-Custom-Header': 'custom-value',
      },
    });

    await providerWithHeaders.image('pixelart-pro').doGenerate({
      prompt,
      n: 1,
      size: undefined,
      aspectRatio: undefined,
      seed: undefined,
      providerOptions: {},
      headers: {
        'X-Request-Header': 'request-value',
      },
      files: undefined,
      mask: undefined,
    });

    expect(server.calls[0].requestHeaders).toMatchObject({
      authorization: 'Bearer test-api-key',
      'x-custom-header': 'custom-value',
      'x-request-header': 'request-value',
    });

    expect(server.calls[0].requestUserAgent).toContain(
      'ai-sdk/pixelart/0.0.0-test',
    );
  });

  it('should warn when aspectRatio is provided', async () => {
    const result = await model.doGenerate({
      prompt,
      n: 1,
      size: undefined,
      aspectRatio: '16:9',
      seed: undefined,
      providerOptions: {},
      files: undefined,
      mask: undefined,
    });

    expect(result.warnings).toStrictEqual([
      {
        type: 'unsupported-setting',
        setting: 'aspectRatio',
        details: 'PixelArt does not support aspect ratio. Use size instead.',
      },
    ]);
  });

  it('should warn when files are provided', async () => {
    const result = await model.doGenerate({
      prompt,
      n: 1,
      size: undefined,
      aspectRatio: undefined,
      seed: undefined,
      providerOptions: {},
      files: [{ type: 'url', url: 'https://example.com/image.png' }],
      mask: undefined,
    });

    expect(result.warnings).toStrictEqual([
      {
        type: 'other',
        message: 'PixelArt does not support image input files.',
      },
    ]);
  });

  it('should warn when mask is provided', async () => {
    const result = await model.doGenerate({
      prompt,
      n: 1,
      size: undefined,
      aspectRatio: undefined,
      seed: undefined,
      providerOptions: {},
      files: undefined,
      mask: { type: 'url', url: 'https://example.com/mask.png' },
    });

    expect(result.warnings).toStrictEqual([
      {
        type: 'other',
        message: 'PixelArt does not support mask input.',
      },
    ]);
  });

  it('should return images decoded from base64', async () => {
    const result = await model.doGenerate({
      prompt,
      n: 1,
      size: undefined,
      aspectRatio: undefined,
      seed: undefined,
      providerOptions: {},
      files: undefined,
      mask: undefined,
    });

    const expected = Uint8Array.from(
      Buffer.from('test-image-data').toString('base64'),
      c => atob(c).charCodeAt(0),
    );

    // Verify images are returned as Uint8Array decoded from b64_json
    expect(result.images).toHaveLength(1);
    expect(result.images[0]).toBeInstanceOf(Uint8Array);
    expect(Buffer.from(result.images[0]).toString()).toBe('test-image-data');
  });

  it('should return response metadata with timestamp and modelId', async () => {
    const modelWithTimestamp = new PixelArtImageModel('pixelart-standard', {
      provider: 'pixelart',
      baseURL: 'https://api.pixelart.ai/v1',
      _internal: { currentDate: () => testDate },
    });

    const result = await modelWithTimestamp.doGenerate({
      prompt,
      n: 1,
      size: undefined,
      aspectRatio: undefined,
      seed: undefined,
      providerOptions: {},
      files: undefined,
      mask: undefined,
    });

    expect(result.response).toStrictEqual({
      timestamp: testDate,
      modelId: 'pixelart-standard',
      headers: expect.any(Object),
    });
  });

  it('should handle API errors', async () => {
    server.urls['https://api.pixelart.ai/*'].response = {
      type: 'error',
      status: 400,
      body: JSON.stringify({
        error: 'Invalid prompt: prompt is too long',
      }),
    };

    await expect(
      model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      }),
    ).rejects.toThrow();

    // Restore for subsequent tests
    server.urls['https://api.pixelart.ai/*'].response = {
      type: 'json-value',
      body: { data: [{ b64_json: TEST_B64 }] },
    };
  });

  it('should handle multiple images (n > 1)', async () => {
    server.urls['https://api.pixelart.ai/*'].response = {
      type: 'json-value',
      body: {
        data: [
          { b64_json: TEST_B64 },
          { b64_json: TEST_B64 },
          { b64_json: TEST_B64 },
        ],
      },
    };

    const result = await model.doGenerate({
      prompt,
      n: 3,
      size: '256x256',
      aspectRatio: undefined,
      seed: undefined,
      providerOptions: {},
      files: undefined,
      mask: undefined,
    });

    expect(result.images).toHaveLength(3);
    result.images.forEach(img => {
      expect(img).toBeInstanceOf(Uint8Array);
      expect(Buffer.from(img).toString()).toBe('test-image-data');
    });

    // Restore default
    server.urls['https://api.pixelart.ai/*'].response = {
      type: 'json-value',
      body: { data: [{ b64_json: TEST_B64 }] },
    };
  });

  it('should omit style and pixelDensity when not provided', async () => {
    await model.doGenerate({
      prompt,
      n: 1,
      size: '128x128',
      aspectRatio: undefined,
      seed: undefined,
      providerOptions: {},
      files: undefined,
      mask: undefined,
    });

    const body = await server.calls[0].requestBodyJson;
    expect(body.style).toBeUndefined();
    expect(body.pixel_density).toBeUndefined();
    expect(body).toStrictEqual({
      prompt,
      n: 1,
      size: '128x128',
    });
  });
});

